user_prompt:
Create a React component that renders the provided state data in a table without using quotation marks in your response

Input: state = {
  data: [
    { name: 'John', age: 20 },
    { name: 'Alice', age: 18 }
  ]
}

answer:
"import React from 'react';

function DataTable({ data }) {
  return (
    <table>
      <thead>
        <tr>
          <th>Name</th>
          <th>Age</th>
        </tr>
      </thead>
      <tbody>
        {data.map((item, index) => (
          <tr key={index}>
            <td>{item.name}</td>
            <td>{item.age}</td>
          </tr>
        ))}
      </tbody>
    </table>
  );
}

export default DataTable;"<|im_end|>

